import React, { useState } from 'react';

export default function DatePicker({ onSelect }) {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState(null);

  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();

  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const firstDay = new Date(year, month, 1).getDay();

  const days = Array.from({ length: daysInMonth }, (_, i) => new Date(year, month, i + 1));
  const blanks = Array.from({ length: firstDay });

  const prevMonth = () => setCurrentDate(new Date(year, month - 1, 1));
  const nextMonth = () => setCurrentDate(new Date(year, month + 1, 1));

  const handleSelect = (day) => {
    setSelectedDate(day);
    if (onSelect) onSelect(day);
  };

  const isToday = (day) => {
    const today = new Date();
    return day.toDateString() === today.toDateString();
  };

  const isSelected = (day) => {
    return selectedDate && day.toDateString() === selectedDate.toDateString();
  };

  const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];

  return (
    <div className="w-80 border border-gray-250 rounded-2xl bg-white shadow-md p-4 select-none font-sans text-sm">
      {/* Month Navigation */}
      <div className="flex items-center justify-between mb-4">
        <button onClick={prevMonth} className="p-1 hover:bg-gray-100 rounded-md">
          <svg className="w-5 h-5 text-gray-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
        </button>
        <span className="font-bold text-gray-800">{monthNames[month]} {year}</span>
        <button onClick={nextMonth} className="p-1 hover:bg-gray-100 rounded-md">
          <svg className="w-5 h-5 text-gray-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" /></svg>
        </button>
      </div>

      {/* Weekday headers */}
      <div className="grid grid-cols-7 text-center font-semibold text-gray-400 mb-2">
        {["Su", "Mo", "Tu", "We", "Th", "Fr", "Sa"].map(d => <span key={d}>{d}</span>)}
      </div>

      {/* Days grid */}
      <div className="grid grid-cols-7 text-center gap-y-1">
        {blanks.map((_, idx) => <span key={idx} />)}
        {days.map((day) => (
          <button
            key={day.getDate()}
            onClick={() => handleSelect(day)}
            className={`w-10 h-10 flex items-center justify-center rounded-lg font-medium transition ${
              isSelected(day)
                ? 'bg-purple-600 text-white hover:bg-purple-700'
                : isToday(day)
                ? 'border-2 border-purple-500 text-purple-600 bg-purple-50/50'
                : 'text-gray-700 hover:bg-gray-100'
            }`}
          >
            {day.getDate()}
          </button>
        ))}
      </div>
    </div>
  );
}
